from pathlib import Path
import torch
import torch.nn.functional as F

bundle = Path('experiments/main/interface_bundles/shared_gating_teacher_packet_smoke_r1')
manifest = json.loads((bundle / 'manifest.json').read_text())
payloads = [torch.load(bundle / frame['packet_relpath'], map_location='cpu') for frame in manifest['frames']]


def score(query, gallery):
    sim = F.normalize(query, dim=1) @ F.normalize(gallery, dim=1).T
    top1 = 0
    mean_rank = 0.0
    for i in range(sim.shape[0]):
        order = torch.argsort(sim[i], descending=True)
        rank = int((order == i).nonzero(as_tuple=False)[0].item()) + 1
        top1 += int(order[0].item() == i)
        mean_rank += rank
    return {'top1_accuracy': top1 / sim.shape[0], 'mean_match_rank': mean_rank / sim.shape[0]}

pred_feat = torch.stack([p['pred_feat'].float().flatten() for p in payloads])
target_feat = torch.stack([p['target_feat'].float().flatten() for p in payloads])
pred_delta = torch.stack([p['pred_delta'].float().flatten() for p in payloads])
target_delta = torch.stack([p['target_delta'].float().flatten() for p in payloads])

weights = [0.0, 0.125, 0.25, 0.5, 1.0, 2.0, 4.0, 8.0]
results = {'sum': {}, 'concat': {}}
for weight in weights:
    results['sum'][str(weight)] = score(pred_feat + weight * pred_delta, target_feat + weight * target_delta)
    results['concat'][str(weight)] = score(
